import pandas as pd
from datetime import datetime

# Cases with SecureAnalytics mentioned (from query_db:20)
secure_analytics_cases = locals().get('var_functions.query_db:20', [])

print("Total SecureAnalytics cases from direct query:", len(secure_analytics_cases))

# Group by month
month_counts = {}
for case in secure_analytics_cases:
    created_date = case.get('createddate', '')
    if created_date:
        try:
            date_obj = datetime.fromisoformat(created_date.replace('Z', '+00:00'))
            month_key = date_obj.strftime('%Y-%m')
            month_name = date_obj.strftime('%B')

            if month_key not in month_counts:
                month_counts[month_key] = {'count': 0, 'month_name': month_name}
            month_counts[month_key]['count'] += 1
        except:
            pass

# Sort by month
sorted_months = sorted(month_counts.items(), key=lambda x: x[0])
print("\nCases by month:")
for month_key, data in sorted_months:
    print(f"  {data['month_name']} ({month_key}): {data['count']} cases")

# Find the month with most cases
if month_counts:
    max_month = max(month_counts.items(), key=lambda x: x[1]['count'])
    print(f"\nMonth with most cases: {max_month[1]['month_name']} ({max_month[1]['count']} cases)")
else:
    print("No cases found")

print('\n__RESULT__:')
print(json.dumps({'max_month': max_month[1]['month_name'] if month_counts else None, 'month_counts': month_counts}))"}

